with open("/root/books/webapp/books.json") as f:
    books = json.load(f)

appended = 0
for b in books:
    if b.get("genre") != "романы":
        continue
    bid = b["id"]
    for i, t in enumerate(b.get("thoughts", [])):
        if bid in appends and i in appends[bid]:
            t["example"] += appends[bid][i]
            appended += 1
    if bid in desc_fixes:
        b["description"] = desc_fixes[bid]

with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",", ":"))

issues = []
for b in books:
    if b.get("genre") != "романы":
        continue
    for i, t in enumerate(b["thoughts"]):
        total = len(t["title"]) + len(t["example"])
        if total < 700 or total > 800:
            issues.append("[%d][%d]=%d" % (b["id"], i, total))
    dlen = len(b.get("description", ""))
    if dlen < 100 or dlen > 150:
        issues.append("desc[%d]=%d" % (b["id"], dlen))

print("Appended %d, %d descriptions" % (appended, len(desc_fixes)))
if issues:
    print("ISSUES:", issues)
else:
    print("All OK!")
